/**
 * parse-issue-signature.mjs — pure parser for extracting cluster signatures
 * from migration-regression GitHub issue bodies.
 *
 * The issue body generated by raise-issues.mjs includes a Markdown table row:
 *   | **Signature** | `<cluster.signature>` |
 *
 * This module is side-effect-free and exported for unit testing.
 */

/**
 * Parse the cluster signature from a migration-regression issue body.
 *
 * Recognises the Markdown table format produced by raise-issues.mjs:
 *   | **Signature** | `<value>` |
 *
 * Also accepts the prose form as a fallback:
 *   **Signature**: `<value>`
 *
 * Returns null when neither pattern is found, signalling that the issue
 * body is malformed or does not follow the expected template (the caller
 * should log it for manual review rather than silently treating it as a
 * no-match).
 *
 * @param {string} body  Raw GitHub issue body text.
 * @returns {string | null}  The signature string, or null if not found.
 */
export function parseIssueSignature(body) {
  if (typeof body !== "string" || body.length === 0) return null;

  // Primary: Markdown table row — | **Signature** | `value` |
  // Allows any whitespace around the pipe-delimited fields.
  const tableMatch = body.match(/\|\s*\*\*Signature\*\*\s*\|\s*`([^`]+)`\s*\|/);
  if (tableMatch) return tableMatch[1];

  // Fallback: prose form — **Signature**: `value`
  const proseMatch = body.match(/\*\*Signature\*\*\s*:\s*`([^`]+)`/);
  if (proseMatch) return proseMatch[1];

  return null;
}
